THE RISK:
{
 "id": "intelligent-subset-inflation",
 "title": "The TAM counts basic and metered PDUs the venture doesn't sell — and Germany's intelligent slice is growing at half the assumed rate",
 "narrative": "The venture sells intelligent rack PDUs; tamBase is scoped as the rack-PDU market, all classes — basic, metered, switched, intelligent. The definitional gap is treated as harmless because 'intelligent is the growth segment'. But the corpus says the intelligent subset is materially smaller than the headline ($2.1B of $2.81B globally at best, with publisher definitions in open contradiction), and — critically — Germany, which carries 50% of the geographic weight, shows intelligent-PDU growth of only 5.2–5.3% CAGR, versus the 9% assumed for the market. Add 60–70% import dependence in Eastern Europe served at low price points, and the CE-relevant intelligent base could be 60–70% of the headline €320M. The venture is sizing the market for a product category it only partially competes in.",
 "category": "boundary",
 "targetNodes": [
  "tamBase"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Product scope (intelligent PDUs) is narrower than the tamBase scope (all rack PDUs): global intelligent-PDU market is sized at $2.1B (2024) against the $2.81B all-class rack-PDU base — roughly a 25–30% haircut before any regional adjustment",
   "refs": [
    "profile:Product",
    "digest:tam-global-crosscheck#c11",
    "digest:tam-global-crosscheck#c0"
   ]
  },
  {
   "step": "propagation",
   "text": "CE demand skews toward the non-intelligent end: Germany's intelligent-PDU segment grows at only 5.2–5.3% CAGR (half the market rate), and Eastern Europe runs 60–70% import dependence consistent with price-led basic/metered purchasing — so the intelligent share of CE spend is lower than the global mix, not higher",
   "refs": [
    "digest:tam-global-crosscheck#c13",
    "digest:tam-global-crosscheck#c14",
    "digest:tam-base#c15"
   ]
  },
  {
   "step": "model-impact",
   "text": "The venture-relevant base is the CE intelligent slice, plausibly ~70% of the €320M headline — every downstream funnel stage (SAM reach, Year-1 obtainable) is computed against demand the product cannot address",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "whyMissable": "'All segments' was an explicit, recorded scoping answer, so the boundary looks deliberately chosen rather than accidentally loose. And because intelligent PDUs are universally described as the fastest-growing segment (IndexBox: 10–12% annually), the definitional gap reads as upside — nobody checks whether the fast-growing slice is also the small slice in the specific geography carrying half the weight.",
 "expectedObviousness": "low",
 "falsifier": "A sourced EU/CE product-class split (Omdia tracker sub-segmentation or IndexBox EU country tables) showing intelligent/switched PDUs at ≥85% of CE rack-PDU revenue.",
 "likelihood": {
  "value": 0.42,
  "rationale": "The intelligent-vs-all-class gap is documented globally, and the Germany sub-global CAGR is a direct datapoint; but publisher definitions of 'intelligent PDU' contradict each other (MRF sizes it larger than the whole rack-PDU market), so the CE haircut magnitude is genuinely uncertain. [evidence revision: Both key premises are now directly confirmed by an independent source (GIA): the $2.1B intelligent-vs-$2.81B all-class gap and the Germany 5.2% CAGR. The Eastern Europe import-dependence figure is also confirmed verbatim by IndexBox. This raises confidence above the prior 0.35. It is not raised higher because the exact CE haircut magnitude remains uncertain — the falsifying EU product-class split is paywalled and unseen, and publisher definitions of 'intelligent PDU' still vary, so the ~70% figure is an estimate rather than a sourced split.]",
  "basis": "evidence",
  "revisedFrom": 0.35
 },
 "perturbation": [
  {
   "nodeId": "tamBase",
   "op": "scale",
   "value": 0.7,
   "note": "Restrict the base to the CE intelligent-PDU slice (~70% of the all-class headline)"
  }
 ],
 "indicators": [
  {
   "signal": "SKU mix (basic/metered vs switched/intelligent) in CE distributor catalogs and price lists",
   "where": "Rittal, Bachmann, and CE master-distributor (e.g., Also/Ingram DC-infrastructure) published price lists",
   "threshold": "Basic+metered SKUs >40% of listed rack-PDU line items in DE/PL catalogs",
   "updates": "increases"
  },
  {
   "signal": "PDU class specified in German and Polish colocation fit-out tenders",
   "where": "Frankfurt colo tender documents; Polish public-sector DC procurement portal (platformazakupowa)",
   "threshold": "≥half of tenders specifying metered-only or basic PDUs",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Obtain the Omdia Rack PDU tracker with product-class sub-segmentation to pin the intelligent share of EU revenue",
   "type": "information",
   "voiNodeId": "tamBase",
   "note": "Directly measures the venture-relevant slice instead of the all-class headline"
  },
  {
   "action": "Add a metered mid-tier SKU to the launch line so the addressable base spans the metered+intelligent classes rather than intelligent-only",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Widens product scope to match the sized market instead of shrinking the market to match the product"
  }
 ],
 "evidenceStatus": "corroborated",
